import React, { useEffect, useState } from 'react';
import api from '../api';

const DoctorList = () => {
  const [doctors, setDoctors] = useState<any[]>([]);
  const [name, setName] = useState('');
  const [spec, setSpec] = useState('');

  const fetchDoctors = () => {
    api.get('doctors/').then((res: any) => setDoctors(res.data));
  };

  useEffect(() => { fetchDoctors(); }, []);

  const handleAdd = async (e: React.FormEvent) => {
    e.preventDefault();
    await api.post('doctors/', { full_name: name, specialization: spec });
    setName(''); setSpec('');
    fetchDoctors();
  };

  const handleDelete = async (id: number) => {
    if (window.confirm("I-remove kini nga doctor?")) {
      await api.delete(`doctors/${id}/`);
      fetchDoctors();
    }
  };

  return (
    <div className="space-y-4">
      <form onSubmit={handleAdd} className="flex gap-2 bg-blue-50 p-4 rounded-lg">
        <input className="border p-2 rounded w-full" placeholder="Doctor Name" value={name} onChange={e => setName(e.target.value)} required />
        <input className="border p-2 rounded w-full" placeholder="Specialization" value={spec} onChange={e => setSpec(e.target.value)} required />
        <button type="submit" className="bg-blue-600 text-white px-4 py-2 rounded">Add Doctor</button>
      </form>
      <table className="min-w-full bg-white shadow rounded-lg">
        <thead className="bg-blue-600 text-white">
          <tr><th className="px-6 py-3 text-left">Name</th><th className="px-6 py-3 text-left">Spec</th><th className="px-6 py-3 text-center">Action</th></tr>
        </thead>
        <tbody>
          {doctors.map((d: any) => (
            <tr key={d.doctor_id} className="border-b">
              <td className="px-6 py-4">{d.full_name}</td>
              <td className="px-6 py-4">{d.specialization}</td>
              <td className="px-6 py-4 text-center">
                <button onClick={() => handleDelete(d.doctor_id)} className="text-red-500">Remove</button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

export default DoctorList;
